/* 登录守卫 — 未登录时跳转到 login.html */
(function () {
  'use strict';

  // login.html 本身不需要守卫
  if (location.pathname.indexOf('login.html') !== -1) return;

  var token = localStorage.getItem('auth_token');

  if (!token) {
    doRedirect();
    return;
  }

  // 检查 token 是否超过 7 天
  var authTime = parseInt(localStorage.getItem('auth_time') || '0');
  if (Date.now() - authTime > 7 * 24 * 3600 * 1000) {
    clearAuth();
    doRedirect();
    return;
  }

  // 可选：向后端验证 token（只在非 GitHub Pages 环境验证）
  if (location.hostname !== 'tiankonghenlan20113046.github.io') {
    var apiBase = '/api';
    fetch(apiBase + '/check-token', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ token: token })
    }).then(function (res) { return res.json(); }).then(function (data) {
      if (!data.valid) {
        clearAuth();
        doRedirect();
      }
    }).catch(function () {
      // 网络错误时不强制退出（可能是 GitHub Pages 无后端）
    });
  }

  function doRedirect() {
    var currentPath = location.pathname.split('/').pop() || 'index.html';
    var qs = location.search || '';
    location.href = 'login.html?redirect=' + encodeURIComponent(currentPath + qs);
  }
})();

function clearAuth() {
  localStorage.removeItem('auth_token');
  localStorage.removeItem('auth_email');
  localStorage.removeItem('auth_time');
}

// 退出登录（供页面调用）
function logout() {
  clearAuth();
  location.href = 'login.html';
}